# =============================================================================
# Helper Functions
# =============================================================================

def bootstrap_ci(data, n_iterations=1000, ci_level=0.95, random_state=42):
    """
    Compute bootstrap confidence interval for mean.

    Parameters:
    - data: 1D array of values
    - n_iterations: Number of bootstrap samples
    - ci_level: Confidence level (0.95 = 95% CI)
    - random_state: Random seed for reproducibility

    Returns:
    - (ci_low, ci_high): Confidence interval bounds
    """
    np.random.seed(random_state)

    bootstrap_means = []

    for _ in range(n_iterations):
        # Resample with replacement
        bootstrap_sample = np.random.choice(data, size=len(data), replace=True)
        bootstrap_means.append(np.mean(bootstrap_sample))

    # Compute percentile-based CI
    alpha = 1.0 - ci_level
    ci_low = np.percentile(bootstrap_means, 100 * alpha / 2)
    ci_high = np.percentile(bootstrap_means, 100 * (1 - alpha / 2))

    return ci_low, ci_high

def compute_cohens_d(group1, group2):
    """
    Compute Cohen's d effect size for difference between two groups.

    Formula: d = (mean1 - mean2) / pooled_sd

    Interpretation:
    - |d| < 0.2: Small effect
    - |d| = 0.2-0.5: Small-medium effect
    - |d| = 0.5-0.8: Medium-large effect
    - |d| > 0.8: Large effect
    """
    mean1, mean2 = np.mean(group1), np.mean(group2)
    sd1, sd2 = np.std(group1, ddof=1), np.std(group2, ddof=1)
    n1, n2 = len(group1), len(group2)

    # Pooled standard deviation
    pooled_sd = np.sqrt(((n1 - 1) * sd1**2 + (n2 - 1) * sd2**2) / (n1 + n2 - 2))

    # Cohen's d
    d = (mean1 - mean2) / pooled_sd

    return d

def interpret_profile(what_mean, where_mean, high_cutoff=0.5, low_cutoff=-0.5):
    """
    Assign interpretable label based on domain z-score patterns.

    Cutoffs: high = +0.5 SD, low = -0.5 SD

    Patterns:
    - Both high: "Generalist - High"
    - Both low: "Generalist - Low"
    - What high, Where low: "What Specialist"
    - Where high, What low: "Where Specialist"
    - Mixed (one high, one medium): Hybrid patterns
    - Both medium: "Average"
    """
    what_level = "High" if what_mean > high_cutoff else ("Low" if what_mean < low_cutoff else "Medium")
    where_level = "High" if where_mean > high_cutoff else ("Low" if where_mean < low_cutoff else "Medium")

    # Pattern-based labels
    if what_level == "High" and where_level == "High":
        return "Generalist - High"
    elif what_level == "Low" and where_level == "Low":
        return "Generalist - Low"
    elif what_level == "High" and where_level == "Low":
        return "What Specialist"
    elif what_level == "Low" and where_level == "High":
        return "Where Specialist"
    elif what_level == "Medium" and where_level == "Medium":
        return "Average"
    else:
        return f"Hybrid ({what_level} What, {where_level} Where)"

